 p_id=>wwv_flow_imp.id(127425975672327813)
,p_lov_name=>'PASSING YEARS'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT TO_CHAR(TRUNC(SYSDATE, ''YYYY'') - (LEVEL - 1) * 365, ''YYYY'') AS DISPLAY_VALUE,',
'       TO_CHAR(TRUNC(SYSDATE, ''YYYY'') - (LEVEL - 1) * 365, ''YYYY'') AS RETURN_VALUE',
'FROM DUAL',
'CONNECT BY LEVEL <= EXTRACT(YEAR FROM SYSDATE) - 1950 + 1',
'ORDER BY DISPLAY_VALUE DESC;'))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_return_column_name=>'DISPLAY_VALUE'
,p_display_column_name=>'RETURN_VALUE'
,p_version_scn=>20721084
);
