wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(123133850006957549)
,p_validation_name=>'10thFilename is not null'
,p_validation_sequence=>20
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_has INTEGER := 0;',
'BEGIN',
'    -- Check if the existing Aadhar Card BLOB has data (length > 0)',
'    SELECT CASE ',
'             WHEN DBMS_LOB.getlength(BL_APPLICANT_10TH_IMG) > 0 THEN 1 ',
'             ELSE 0 ',
'           END',
'    INTO v_has',
'    FROM APPLICANT_UPLOAD_DOC',
'    WHERE NU_DOC_ID = :P2_NU_DOC_ID;',
'',
'    -- Scenario 1: No existing Aadhar Card and no new upload',
'    IF v_has = 0 AND :P2_10TH_MARK_SHEET_AND_CERTIFICATE_FILE IS NULL THEN',
'        RETURN ''Please upload 10th Mark Sheet'';',
'',
'    -- Scenario 2: Aadhar Card exists, but no new file is uploaded',
'    ELSIF v_has = 1 AND :P2_10TH_MARK_SHEET_AND_CERTIFICATE_FILE IS NULL THEN',
'        RETURN NULL; -- Allow saving without uploading again',
'',
