'    END IF;',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        -- No row exists, treat as new',
'        IF :P2_10TH_MARK_SHEET_AND_CERTIFICATE_FILE IS NULL THEN',
'            RETURN ''Please upload 10th Mark Sheet'';',
'        ELSE',
'            RETURN NULL;',
'        END IF;',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
