wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(123142568793957552)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Insert'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE ',
'    -- Bank',
'    BL_FILE_BANK BLOB;',
'    MIME_TYPE_BANK VARCHAR2(1000);',
'    FILENAME_BANK VARCHAR2(1000);',
'',
'    -- Appointment',
'    BL_FILE_APPOINTMENT BLOB;',
'    MIME_TYPE_APPOINTMENT VARCHAR2(1000);',
'    FILENAME_APPOINTMENT VARCHAR2(1000);',
'',
'    -- 10th',
'    BL_FILE_10TH BLOB;',
'    MIME_TYPE_10TH VARCHAR2(1000);',
'    FILENAME_10TH VARCHAR2(1000);',
'',
'    -- 12th',
'    BL_FILE_12TH BLOB;',
'    MIME_TYPE_12TH VARCHAR2(1000);',
'    FILENAME_12TH VARCHAR2(1000);',
'',
'    -- Aadhar',
'    BL_FILE_AADHAR BLOB;',
'    MIME_TYPE_AADHAR VARCHAR2(1000);',
'    FILENAME_AADHAR VARCHAR2(1000);',
'',
'    -- PAN',
'    BL_FILE_PAN BLOB;',
'    MIME_TYPE_PAN VARCHAR2(1000);',
'    FILENAME_PAN VARCHAR2(1000);',
'',
'    -- Resume',
'    BL_FILE_RESUME BLOB;',
'    MIME_TYPE_RESUME VARCHAR2(1000);',
'    FILENAME_RESUME VARCHAR2(1000);',
'',
'    -- COVID',
'    BL_FILE_COVID BLOB;',
'    MIME_TYPE_COVID VARCHAR2(1000);',
'    FILENAME_COVID VARCHAR2(1000);',
'',
'    -- Passport',
'    BL_FILE_PASSPORT BLOB;',
'    MIME_TYPE_PASSPORT VARCHAR2(1000);',
'    FILENAME_PASSPORT VARCHAR2(1000);',
'',
'    --others',
'    BL_FILE_OTHERS BLOB;',
'    MIME_TYPE_OTHERS VARCHAR2(1000);',
'    FILENAME_OTHERS VARCHAR2(1000);',
'',
'    BL_FILE_SEMESTER BLOB;',
'    MIME_TYPE_SEMESTER VARCHAR2(1000);',
'    FILENAME_SEMESTER VARCHAR2(1000);',
'',
'    v_doc_id NUMBER;',
'BEGIN',
'    -- Each SELECT wrapped safely',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_BANK, MIME_TYPE_BANK, FILENAME_BANK',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_PAYSLIP_BANK_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_APPOINTMENT, MIME_TYPE_APPOINTMENT, FILENAME_APPOINTMENT',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_APPOINTMENT_LETTER_OF_PREVIOUS_ORGANIZATION_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_10TH, MIME_TYPE_10TH, FILENAME_10TH',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_10TH_MARK_SHEET_AND_CERTIFICATE_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_12TH, MIME_TYPE_12TH, FILENAME_12TH',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_12TH_MARK_SHEET_AND_CERTIFICATE_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_AADHAR, MIME_TYPE_AADHAR, FILENAME_AADHAR',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_AADHAR_CARD_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_PAN, MIME_TYPE_PAN, FILENAME_PAN',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_PAN_CARD_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_RESUME, MIME_TYPE_RESUME, FILENAME_RESUME',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_UPDATED_RESUME_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_COVID, MIME_TYPE_COVID, FILENAME_COVID',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_COVID_CERTIFICATE_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_PASSPORT, MIME_TYPE_PASSPORT, FILENAME_PASSPORT',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_PASSPORT_COPY_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'   ',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_OTHERS, MIME_TYPE_OTHERS, FILENAME_OTHERS',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_OTHER_DOCUMENT_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'      BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO BL_FILE_SEMESTER, MIME_TYPE_SEMESTER, FILENAME_SEMESTER',
'        FROM apex_application_temp_files',
'        WHERE name = :P2_ALL_SEMESTER_MARK_SHEET_FILE;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;',
'    END;',
'',
'    SELECT NVL(MAX(NU_DOC_ID), 0) + 1',
'    INTO v_doc_id',
'    FROM APPLICANT_UPLOAD_DOC;',
'',
'',
'    INSERT INTO APPLICANT_UPLOAD_DOC (',
'        VC_COMP_CODE,',
'        VC_DEFAULT_COMP,',
'        VC_APPLICANT_ID,',
'        VC_AUTH_CODE,',
'        DT_DATE,',
'        NU_DOC_ID,',
'        VC_REQUIRED_DOCUMENTS,',
'        BL_APPLICANT_BANK_IMG, MIMETYPE_BANK, FILENAME_BANK,',
'        BL_APPLICANT_APPOINTMENT_IMG, MIMETYPE_APPOINTMENT, FILENAME_APPOINTMENT,',
'        BL_APPLICANT_10TH_IMG, MIMETYPE_10TH, FILENAME_10TH,',
'        BL_APPLICANT_12TH_IMG, MIMETYPE_12TH, FILENAME_12TH,',
'        BL_APPLICANT_AADHAR_IMG, MIMETYPE_AADHAR, FILENAME_AADHAR,',
'        BL_APPLICANT_PAN_IMG, MIMETYPE_PAN, FILENAME_PAN,',
'        BL_APPLICANT_RESUME_IMG, MIMETYPE_RESUME, FILENAME_RESUME,',
'        BL_APPLICANT_COVID_IMG, MIMETYPE_COVID, FILENAME_COVID,',
'        BL_APPLICANT_PASSPORT_IMG, MIMETYPE_PASSPORT, FILENAME_PASSPORT,',
'        BL_APPLICANT_OTHERS_IMG, MIMETYPE_OTHERS, FILENAME_OTHERS,',
'        BL_APPLICANT_ALL_SEMESTER_IMG,MIMETYPE_ALL_SEMESTER,FILENAME_ALL_SEMESTER,',
'        DT_CREATED_AT,',
'        VC_CREATED_BY',
'    )',
'    VALUES (',
'        :GLOBAL_COMP_CODE,',
'        :GLOBAL_COMP_CODE,',
'         :APPLICANT_ID,',
'         :GLOBAL_USER_CODE,',
'        To_date(:P2_DATE,''DD-MON-YYYY''),',
'        v_doc_id,',
'        :P2_REQUIRED_DOCUMENTS,',
'        BL_FILE_BANK, MIME_TYPE_BANK, FILENAME_BANK,',
'        BL_FILE_APPOINTMENT, MIME_TYPE_APPOINTMENT, FILENAME_APPOINTMENT,',
'        BL_FILE_10TH, MIME_TYPE_10TH, FILENAME_10TH,',
'        BL_FILE_12TH, MIME_TYPE_12TH, FILENAME_12TH,',
'        BL_FILE_AADHAR, MIME_TYPE_AADHAR, FILENAME_AADHAR,',
'        BL_FILE_PAN, MIME_TYPE_PAN, FILENAME_PAN,',
'        BL_FILE_RESUME, MIME_TYPE_RESUME, FILENAME_RESUME,',
'        BL_FILE_COVID, MIME_TYPE_COVID, FILENAME_COVID,',
'        BL_FILE_PASSPORT, MIME_TYPE_PASSPORT, FILENAME_PASSPORT,',
'        BL_FILE_OTHERS, MIME_TYPE_OTHERS, FILENAME_OTHERS,',
'        BL_FILE_SEMESTER, MIME_TYPE_SEMESTER, FILENAME_SEMESTER,',
'        SYSDATE,',
'        :GLOBAL_USER_CODE',
'    );',
'        UPDATE TEMP_USER SET CH_ACTIVE = ''N'' ',
'    WHERE upper(VC_USER_NAME) = upper(:APP_USER);',
' END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(123121736366957530)
,p_internal_uid=>74579644759447534
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(123143000051957553)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'GET DATA'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'begin',
'select ',
'       DT_DATE,',
'       NU_DOC_ID,',
'        VC_REQUIRED_DOCUMENTS',
'   into ',
'   :P2_DATE,',
'   :P2_NU_DOC_ID,',
'    :P2_REQUIRED_DOCUMENTS',
'  from APPLICANT_UPLOAD_DOC where',
'  vc_comp_code = :GLOBAL_COMP_CODE and NU_DOC_ID =:P2_NU_DOC_ID;',
'  exception when NO_DATA_FOUND then NULL;',
'  end;'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P2_MODE'
,p_process_when_type=>'VAL_OF_ITEM_IN_COND_NOT_EQ_COND2'
,p_process_when2=>'A'
,p_internal_uid=>74580076017447535
);
end;
