,p_html_page_header=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div id="customConfirm" style="display:none; position:fixed; top:50%; left:50%; transform:translate(-50%, -50%); background:#fff; border:1px solid #ccc; padding:20px; z-index:1000;">',
'    <p id="confirmMessage"></p>',
