'//// Aloowed only number ///',
'document.addEventListener("DOMContentLoaded", function() {',
'    // Function to restrict input to numbers',
'    function allowOnlyNumbers(field) {',
'        // Add an event listener for keypress',
'        field.addEventListener(''keypress'', function(event) {',
'            var charCode = event.charCode || event.keyCode;',
'            // Allow only numbers (0-9) and control keys like backspace',
'            if (charCode < 48 || charCode > 57) {',
'                event.preventDefault(); // Prevent invalid input',
'            }',
'        });',
'',
'        // Add an event listener for paste to handle pasted content',
'        field.addEventListener(''paste'', function(event) {',
'            var pasteData = event.clipboardData.getData(''text'');',
'            // Prevent pasting non-numeric characters',
'            if (!/^\d+$/.test(pasteData)) {',
'                event.preventDefault();',
'            }',
'        });',
'    }',
'',
'    // Add restrictions to each field',
'    var fields = [',
'        document.getElementById(''P8_NUM_MONTHLY_INCOME''),',
'        document.getElementById(''P8_NUM_SALARY''),',
'        document.getElementById(''P8_NUM_PERCENTAGE''),',
'        document.getElementById(''P8_VC_PERM_CONTACT''),',
'        document.getElementById(''P8_VC_CONTACT'')',
'    ];',
'',
'    // Apply the restriction to each field if it exists',
'    fields.forEach(function(field) {',
'        if (field) {',
'            allowOnlyNumbers(field);',
'        }',
'    });',
'});',
'',
