'function validateJoiningAndLeavingDates() {',
'    // Get the values of the joining and leaving date page items',
'    var joiningDate = $v("P8_DT_JOINING_DATE"); ',
'    var leavingDate = $v("P8_DT_LEAVING_DATE"); ',
'',
'    // Check if both dates are provided',
'    if (joiningDate && leavingDate) {',
'        // Convert to Date objects for comparison',
'        var joining = new Date(joiningDate);',
'        var leaving = new Date(leavingDate);',
'',
'        // Validate: Joining date should not be greater than Leaving date',
'        if (joining > leaving) {',
