'    var passingYear = document.getElementById(''P8_VC_PASSING_YEAR'').value;',
'    var percentage = document.getElementById(''P8_NUM_PERCENTAGE'').value;',
'',
'    // Check each field and display an alert if any field is empty',
'    if (degree === "") {',
'        alert("Degree can not be null");',
'        return false; // Prevent form submission',
'    }',
'',
'    if (mainSubject === "") {',
'        alert("Main Subject can not be null");',
'        return false; // Prevent form submission',
'    }',
'',
'    if (instituteName === "") {',
'        alert("Institute can not be null");',
'        return false; // Prevent form submission',
'    }',
'',
'    if (duration === "") {',
'        alert("Duration can not be null");',
'        return false; // Prevent form submission',
'    }',
'',
'    if (passingYear === "") {',
'        alert("Passing Year can not be null");',
'        return false; // Prevent form submission',
'    }',
'',
'    if (percentage === "") {',
'        alert("Percentage can not be null");',
'        return false; // Prevent form submission',
'    }',
'',
'    // If all validations pass, allow form submission',
'    return true;',
'}',
'',
'',
'',
''))
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
