wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(140846615554941888)
,p_plug_name=>'Final Print Details'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(191108159280225600)
,p_plug_display_sequence=>130
,p_location=>null
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  -- Variables for personal details',
'  v_VC_COMP_CODE            VARCHAR2(2);',
'  v_VC_DEFAULT_COMP         VARCHAR2(2);',
'  v_VC_APPLICANT_ID         VARCHAR2(16);',
'  v_VC_NAME                 VARCHAR2(100);',
'  v_VC_FATHER_HUSBAND       VARCHAR2(100);',
'  v_DT_DOB                  DATE;',
'  v_VC_PRESENT_ADDR         VARCHAR2(500);',
'  v_VC_CONTACT              VARCHAR2(15);     ',
'  v_VC_EMAIL                VARCHAR2(100);',
'  v_VC_PERM_ADDR            VARCHAR2(500);   ',
'  v_VC_PERM_CONTACT         VARCHAR2(15);',
'  v_VC_GENDER               CHAR(2);',
'  v_VC_MARITAL_STATUS       VARCHAR2(20);',
'  v_VC_HOMETOWN             VARCHAR2(100);',
'  v_VC_EXPERTISE            VARCHAR2(200);',
'  v_VC_AUTH_CODE            VARCHAR2(10);',
'  v_DT_MOD_DATE             DATE;',
'  v_CH_EXP_STATUS           CHAR(1);',
'',
'  -- Variables for education details (using collections)',
'  TYPE qualification_record_type IS RECORD (',
'    VC_QUALIFICATION_ID     VARCHAR2(5),',
'    VC_INSTITUTE_NAME       VARCHAR2(200),',
'    VC_DEGREE               VARCHAR2(50),',
'    VC_MAIN_SUBJECT         VARCHAR2(50),',
'    VC_DURATION             VARCHAR2(50),',
'    VC_PASSING_YEAR         VARCHAR2(4),',
'    NU_PERCENTAGE           NUMBER(5,2),',
'    VC_EDU_AUTH_CODE        VARCHAR2(10),',
'    DT_MOD_DATE             DATE',
'  );',
'',
'  -- Variables for additional courses',
'  TYPE course_record_type IS RECORD (',
'    VC_COURSE_ID            VARCHAR2(5),',
'    VC_INSTITUTION          VARCHAR2(100),',
'    VC_COURSE_NAME          VARCHAR2(100),',
'    VC_COURSE_DURATION      VARCHAR2(50),',
'    DT_COMPLETION_DATE      DATE',
'  );',
'',
'   -- Variables for employment details',
'  TYPE employment_record_type IS RECORD (',
'    VC_EMPLOYMENT_ID        VARCHAR2(5),',
'    VC_EMPLOYER_NAME        VARCHAR2(100),',
'    VC_LOCATION             VARCHAR2(100),',
'    VC_COUNTRY              VARCHAR2(100),',
'    VC_STATE                VARCHAR2(100), ',
'    DT_JOINING_DATE         DATE,',
'    DT_LEAVING_DATE         DATE,',
'    VC_DESIGNATION          VARCHAR2(50),',
'    NUM_SALARY              NUMBER,',
'    CH_CURRENT_EMPLOYER     CHAR(1) -- New field for current employer status',
'  );',
'',
' -- Variables for family details (using collections)',
'  TYPE family_record_type IS RECORD (',
'    VC_FAMILY_ID            VARCHAR2(5),',
'    VC_NAME                 VARCHAR2(100),',
'    VC_RELATION             VARCHAR2(50),',
'    VC_OCCUPATION           VARCHAR2(100),',
'    VC_DEPARTMENT           VARCHAR2(50),',
'    VC_DESIGNATION_FAMILY   VARCHAR2(50),',
'    NU_MONTHLY_INCOME       NUMBER',
'  );',
'',
'  TYPE qualification_table_type IS TABLE OF qualification_record_type;',
'  TYPE course_table_type IS TABLE OF course_record_type;',
'  TYPE employment_table_type IS TABLE OF employment_record_type;',
'  TYPE family_table_type IS TABLE OF family_record_type;',
'',
'  qualifications qualification_table_type;  -- Variable to store the fetched qualifications',
'  courses course_table_type;                -- Variable to store the fetched courses',
'  employments employment_table_type;        -- Variable to store the fetched employment details',
'  family_details family_table_type;  -- Variable to store the fetched family details',
'',
'BEGIN',
'  -- Fetch the applicant details from the "APPLICANT_DETAILS" table based on applicant ID',
'  SELECT VC_COMP_CODE, VC_DEFAULT_COMP, VC_APPLICANT_ID, VC_NAME, VC_FATHER_HUSBAND, ',
'         DT_DOB, VC_PRESENT_ADDR, VC_CONTACT, VC_EMAIL, VC_PERM_ADDR, VC_PERM_CONTACT, ',
'         VC_GENDER, VC_MARITAL_STATUS, VC_HOMETOWN, VC_EXPERTISE, VC_AUTH_CODE, ',
'         DT_MOD_DATE, CH_EXP_STATUS',
'    INTO v_VC_COMP_CODE, v_VC_DEFAULT_COMP, v_VC_APPLICANT_ID, v_VC_NAME, v_VC_FATHER_HUSBAND, ',
'         v_DT_DOB, v_VC_PRESENT_ADDR, v_VC_CONTACT, v_VC_EMAIL, v_VC_PERM_ADDR, v_VC_PERM_CONTACT, ',
'         v_VC_GENDER, v_VC_MARITAL_STATUS, v_VC_HOMETOWN, v_VC_EXPERTISE, v_VC_AUTH_CODE, ',
'         v_DT_MOD_DATE, v_CH_EXP_STATUS',
'    FROM APPLICANT_DETAILS',
'   WHERE VC_APPLICANT_ID = :VC_APPLICANT_ID;',
'',
'  -- Fetch the education details from the "EDUCATIONAL_QUALIFICATIONS" table based on applicant ID',
'  SELECT VC_QUALIFICATION_ID, VC_INSTITUTE_NAME, get_degree_name(VC_DEGREE), VC_MAIN_SUBJECT,',
'         VC_DURATION, VC_PASSING_YEAR, NU_PERCENTAGE, VC_AUTH_CODE, DT_MOD_DATE',
'    BULK COLLECT INTO qualifications',
'    FROM EDUCATIONAL_QUALIFICATIONS',
'   WHERE VC_APPLICANT_ID = :VC_APPLICANT_ID;',
'',
'  -- Fetch the additional courses details from the "ADDITIONAL_COURSES" table based on applicant ID',
'  SELECT VC_COURSE_ID, VC_INSTITUTION, VC_COURSE_NAME, VC_DURATION, DT_COMPLETION_DATE',
'    BULK COLLECT INTO courses',
'    FROM ADDITIONAL_COURSES',
'   WHERE VC_APPLICANT_ID = :VC_APPLICANT_ID;',
'',
'  -- Fetch the employment details from the "EMPLOYMENT_DETAILS" table based on applicant ID',
'  SELECT VC_EMPLOYMENT_ID, VC_EMPLOYER_NAME, get_city_name(VC_LOCATION), get_country_name(VC_COUNTRY), ',
'         get_state_name(VC_STATE), DT_JOINING_DATE, DT_LEAVING_DATE,VC_DESIGNATION, NUM_SALARY, CH_CURRENT_EMPLOYER',
'    BULK COLLECT INTO employments',
'    FROM EMPLOYMENT_DETAILS',
'   WHERE VC_APPLICANT_ID = :VC_APPLICANT_ID;   ',
'',
'  -- Fetch the family details from the "FAMILY_DETAILS" table based on applicant ID',
'  SELECT VC_FAMILY_ID, VC_NAME, VC_RELATION, VC_OCCUPATION, VC_DEPARTMENT, VC_DESIGNATION, NU_MONTHLY_INCOME',
'    BULK COLLECT INTO family_details',
'    FROM FAMILY_DETAILS',
'   WHERE VC_APPLICANT_ID = :VC_APPLICANT_ID;',
'',
'    -- Print the static logo and company details in one row with centered company details',
'   htp.p(''<div style="display: flex; align-items: center; justify-content: flex-start; width: 100%;">'');',
'',
'  -- Logo (left side)',
'  htp.p(''<div style="padding-left:2px;">'');',
'  htp.p(''<img src="#APP_FILES#EASTERN SOFTWARE SOLUTIONS LOGO.jpg" alt="Company Logo" style="width:250px; height:auto;">'');  -- Adjust width and height as needed',
'  htp.p(''</div>'');',
'',
'  -- Spacer div to ensure the company details are centered but slightly shifted to the left',
'  htp.p(''<div style="flex-grow: 1; text-align: center; margin-left: -0px;">'');  -- Adjust the margin to shift left',
'',
'  -- Company details (centered but slightly shifted left)',
'  htp.p(''<h1 style="font-size:15px; font-weight:bold; color: #000000;">'');',
'  htp.p(''Eastern Software Solutions Private Limited<br>'');',
unistr('  htp.p(''B - 65, Sector - 63, Noida \2013 201307, Uttar Pradesh<br>'');'),
'  htp.p(''Tel: + 91 (120) 4212931 - 39, Web: www.essindia.com'');',
'  htp.p(''</h1>'');',
'',
'  htp.p(''</div>'');  -- End of the spacer div',
'',
'  -- Applicant image (right side)',
'  htp.p(''<div style="text-align: right; padding-right: 10px;">'');',
'--   htp.p(''<img src="#APP_FILES#EASTERN SOFTWARE SOLUTIONS LOGO.jpg" alt="Applicant Image" style="width:250px; height:auto;">'');  -- Adjust width and height as needed',
'  htp.p(''<img src="http://localhost:8080/ords/wsts/IMG/APP/'' || :VC_APPLICANT_ID || ''" alt="Applicant Image" style="width:120px; height:130px; object-fit: cover;"/>'');',
'  htp.p(''</div>'');  -- End applicant image div',
'',
'  htp.p(''</div>'');  -- End the flex container',
'  htp.p(''<br>'');',
'  ',
'  htp.p(''<br>'');',
'   ',
'  -- Print the retrieved personal details in a table format',
'  htp.p(''<p>'');',
'  htp.p(''<h1 style="font-size:17px;font-weight:bold; text-align:center;">PERSONAL DETAILS</h1>'');',
'  htp.p(''<table border="1" style="width:100%; border-collapse: collapse;" id="myTable">'');',
'',
'  -- Add CSS for alternating row colors (light sky blue and white)',
'  htp.p(''<style>'');',
'  htp.p(''tr:nth-child(even) {background-color: lightblue;}'');',
'  htp.p(''tr:nth-child(odd) {background-color: white;}'');',
'  htp.p(''</style>'');',
'',
'  -- Personal details rows',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Name</td><td style="font-size:13px;">'' || v_VC_NAME || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Father/Husband</td><td style="font-size:13px;">'' || v_VC_FATHER_HUSBAND || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Date of Birth</td><td style="font-size:13px;">'' || TO_CHAR(v_DT_DOB, ''DD-Mon-YYYY'') || ''</td>'');',
'  htp.p(''</tr>'');',
'',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Present Address</td><td style="font-size:13px;">'' || v_VC_PRESENT_ADDR || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Contact No</td><td style="font-size:13px;">'' || v_VC_CONTACT || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Email</td><td style="font-size:13px;">'' || v_VC_EMAIL || ''</td>'');',
'  htp.p(''</tr>'');',
'',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Permanent Address</td><td style="font-size:13px;">'' || v_VC_PERM_ADDR || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Permanent Contact</td><td style="font-size:13px;">'' || v_VC_PERM_CONTACT || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Gender</td><td style="font-size:13px;">'' || CASE WHEN v_VC_GENDER = ''M'' THEN ''Male'' ',
'        WHEN v_VC_GENDER = ''F'' THEN ''Female'' WHEN v_VC_GENDER = ''O'' THEN ''Other'' ELSE ''Unknown'' END || ''</td>'');',
'  htp.p(''</tr>'');',
'  ',
'',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Marital Status</td><td style="font-size:13px;">'' || ',
'      CASE WHEN v_VC_MARITAL_STATUS = ''M'' THEN ''Married'' WHEN v_VC_MARITAL_STATUS = ''S'' THEN ''Single'' ELSE ''Unknown'' END || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Hometown</td><td style="font-size:13px;">'' || v_VC_HOMETOWN || ''</td>'');',
'  htp.p(''<td style="font-size:13px; font-weight: bold; font-family:arial;">Expertise</td><td style="font-size:13px;">'' || v_VC_EXPERTISE || ''</td>'');',
'  htp.p(''</tr>'');',
'',
'  -- End the personal details table',
'  htp.p(''</table>'');',
'',
'-- Print the retrieved education details in a table format',
'htp.p(''<h1 style="font-size:17px;font-weight:bold; text-align:center;">EDUCATIONAL DETAILS</h1>'');',
'htp.p(''<table border="1" style="width:100%; border-collapse: collapse;" id="myTable">'');',
'',
'-- Start the education details table header',
'htp.p(''<tr>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Institute Name</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Degree</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Main Subject</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Duration</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Passing Year</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Percentage</th>',
'</tr>'');',
'',
'-- Loop through the qualifications collection and display each record',
'FOR i IN 1..qualifications.COUNT LOOP',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || qualifications(i).VC_INSTITUTE_NAME || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || qualifications(i).VC_DEGREE || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || qualifications(i).VC_MAIN_SUBJECT || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || qualifications(i).VC_DURATION || ''</td>''); -- Center aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || qualifications(i).VC_PASSING_YEAR || ''</td>''); -- Center aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || qualifications(i).NU_PERCENTAGE || ''</td>''); -- Center aligned',
'  htp.p(''</tr>'');',
'END LOOP;',
'',
'-- End the education details table',
'htp.p(''</table>'');',
'',
'',
'-- Print the retrieved additional courses details in a table format',
'htp.p(''<h1 style="font-size:17px;font-weight:bold; text-align:center;">ADDITIONAL COURSES</h1>'');',
'htp.p(''<table border="1" style="width:100%; border-collapse: collapse;" id="myTable">'');',
'',
'-- Start the courses table header',
'htp.p(''<tr>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Institution</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Course Name</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Duration</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Completion Date</th>',
'</tr>'');',
'',
'-- Loop through the courses collection and display each record',
'FOR i IN 1..courses.COUNT LOOP',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || courses(i).VC_INSTITUTION || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || courses(i).VC_COURSE_NAME || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || courses(i).VC_COURSE_DURATION || ''</td>''); -- Center aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || TO_CHAR(courses(i).DT_COMPLETION_DATE, ''DD-Mon-YYYY'') || ''</td>''); -- Center aligned',
'  htp.p(''</tr>'');',
'END LOOP;',
'',
'-- End the courses details table',
'htp.p(''</table>'');',
'',
'',
'-- Print the retrieved employment details in a table format',
'htp.p(''<h1 style="font-size:17px;font-weight:bold; text-align:center;">EMPLOYMENT DETAILS</h1>'');',
'htp.p(''<table border="1" style="width:100%; border-collapse: collapse;" id="myTable">'');',
'',
'-- Start the employment table header',
'htp.p(''<tr>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Employer Name</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Current Employer</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Joining Date</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Leaving Date</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Designation</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Salary</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Country</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">State</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Location</th>',
'</tr>'');',
'',
'-- Loop through the employment collection and display each record',
'FOR i IN 1..employments.COUNT LOOP',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || employments(i).VC_EMPLOYER_NAME || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || CASE WHEN employments(i).CH_CURRENT_EMPLOYER = ''Y'' THEN ''Yes'' ',
'        WHEN employments(i).CH_CURRENT_EMPLOYER = ''N'' THEN ''No'' ELSE employments(i).CH_CURRENT_EMPLOYER END || ''</td>'');',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || TO_CHAR(employments(i).DT_JOINING_DATE, ''DD-Mon-YYYY'') || ''</td>''); -- Center aligned (Date)',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || TO_CHAR(employments(i).DT_LEAVING_DATE, ''DD-Mon-YYYY'') || ''</td>''); -- Center aligned (Date)',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || employments(i).VC_DESIGNATION || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || employments(i).NUM_SALARY || ''</td>''); -- Center aligned (Number)',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || employments(i).VC_COUNTRY || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || employments(i).VC_STATE || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || employments(i).VC_LOCATION || ''</td>''); -- Left aligned',
'  htp.p(''</tr>'');',
'END LOOP;',
'',
'-- End the employment details table',
'htp.p(''</table>'');',
'',
'-- Print the retrieved family details in a table format',
'htp.p(''<h1 style="font-size:17px;font-weight:bold; text-align:center;">FAMILY DETAILS</h1>'');',
'htp.p(''<table border="1" style="width:100%; border-collapse: collapse;" id="myTable">'');',
'',
'-- Start the family details table header',
'htp.p(''<tr>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Family Name</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Relation</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Occupation</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Department</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:left;">Designation</th>',
'    <th style="font-size:13px; font-weight: bold; font-family:arial; background-color:#f2f2f2; text-align:center;">Monthly Income</th>',
'</tr>'');',
'',
'-- Loop through the family details collection and display each record',
'FOR i IN 1..family_details.COUNT LOOP',
'  htp.p(''<tr>'');',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || family_details(i).VC_NAME || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || family_details(i).VC_RELATION || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || family_details(i).VC_OCCUPATION || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || family_details(i).VC_DEPARTMENT || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:left;">'' || family_details(i).VC_DESIGNATION_FAMILY || ''</td>''); -- Left aligned',
'  htp.p(''<td style="font-size:13px; text-align:center;">'' || family_details(i).NU_MONTHLY_INCOME || ''</td>''); -- Center aligned',
'  htp.p(''</tr>'');',
'END LOOP;',
'',
'-- End the family details table',
'htp.p(''</table>'');',
'',
'END;',
''))
,p_plug_source_type=>'NATIVE_PLSQL'
,p_required_patch=>wwv_flow_imp.id(191026032852225521)
,p_ai_enabled=>false
);
