wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(136670997336740250)
,p_validation_name=>'VALIDATION'
,p_validation_sequence=>10
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'IF :P8_VC_NAME IS NULL THEN',
'RETURN ''Name can not be null'';',
'END IF;',
'',
'IF :P8_VC_FATHER_HUSBAND IS NULL THEN',
'RETURN ''Father/Husband can not be null'';',
'END IF;',
'',
'IF :P8_DT_DOB IS NULL THEN',
'RETURN ''DOB can not be null'';',
'END IF;',
'',
'-- Check if Contact Number is null',
'IF :P8_VC_CONTACT IS NULL THEN',
'    RETURN ''Contact Number can not be null'';',
'-- Check if Contact Number contains only numeric characters',
'ELSIF NOT REGEXP_LIKE(:P8_VC_CONTACT, ''^\d+$'') THEN',
'    RETURN ''Contact number must be numeric'';',
'END IF;',
'',
'IF :P8_VC_PRESENT_ADDR IS NULL THEN',
'RETURN ''Present Addr can not be null'';',
'END IF;',
'',
'-- Check if Email is null',
'IF :P8_VC_EMAIL IS NULL THEN',
'    RETURN ''Email can not be null'';',
'-- Check if Email has a valid format with domain (like @gmail.com)',
'ELSIF NOT REGEXP_LIKE(:P8_VC_EMAIL, ''^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$'') THEN',
'    RETURN ''Please enter a valid email address with domain (e.g., user@example.com)'';',
'END IF;',
'',
'IF :P8_VC_PERM_ADDR IS NULL THEN',
'RETURN ''Permanent Address can not be null'';',
'END IF;',
'',
'IF :P8_VC_GENDER IS NULL THEN',
'RETURN ''Gender can not be null'';',
'END IF;',
'',
'IF :P8_VC_MARITAL_STATUS IS NULL THEN',
'RETURN ''Martial status can not be null'';',
'END IF;',
'',
'IF :P8_VC_HOMETOWN IS NULL THEN',
'RETURN ''Hometown can not be null'';',
'END IF;',
'',
'-- Check if Per Contact Number is null',
'-- IF :P8_VC_PERM_CONTACT IS NULL THEN',
'--     RETURN ''Permanent contact Number can not be null'';',
'-- -- Check if Per Contact Number contains only numeric characters',
'-- ELSIF NOT REGEXP_LIKE(:P8_VC_PERM_CONTACT, ''^\d+$'') THEN',
'--     RETURN ''Permanent contact number must be numeric'';',
'-- END IF;',
'',
'IF :P8_VC_EXPERTISE IS NULL THEN',
'RETURN ''Experties can not be null'';',
'END IF;',
'',
'IF :P8_FRE_EXP IS NULL THEN',
'RETURN ''Fresher/Experience can not be null'';',
'END IF;',
'',
'',
'DECLARE',
'    v_row_count_1 NUMBER;',
'    v_row_count_2 NUMBER;',
'    v_row_count_3 NUMBER;',
'    v_count NUMBER;',
'BEGIN',
'    -- Check the number of rows in the QUALIFICATION_DTL collection',
'    SELECT COUNT(*)',
'    INTO v_row_count_1',
'    FROM apex_collections',
'    WHERE collection_name = ''QUALIFICATION_DTL'';',
'',
'    -- Check the number of rows in the EMPLOYMENT_DTL collection',
'    SELECT COUNT(*)',
'    INTO v_row_count_2',
'    FROM apex_collections',
'    WHERE collection_name = ''EMPLOYMENT_DTL'';',
'',
'    -- Check the number of rows in the FAMILY_DETAILS_COLLECTION collection',
'    SELECT COUNT(*)',
'    INTO v_row_count_3',
'    FROM apex_collections',
'    WHERE collection_name = ''FAMILY_DETAILS_COLLECTION'';',
'',
'    -- If no rows in any of the collections, raise an error',
'    IF v_row_count_1 < 3 THEN',
'        RETURN ''At least three qualification is required'';',
'    ELSIF v_row_count_2 = 0 AND :P8_FRE_EXP = ''E'' THEN',
'        RETURN ''At least one employment record is required'';',
'    ELSIF v_row_count_3 = 0 THEN',
'        RETURN ''At least one family detail is required'';',
'    END IF;',
'',
'   exception when others then',
'   RETURN ''Error while validating collections: '' || SQLERRM;',
'END;',
'',
'DECLARE',
'    v_count NUMBER;',
'BEGIN',
'    SELECT COUNT(*) INTO v_count ',
'    FROM APPLICANT_DETAILS ',
'    WHERE UPPER(TRIM(VC_EMAIL)) = UPPER(TRIM(:P8_VC_EMAIL));',
'',
'    IF v_count > 0 THEN ',
'        RETURN ''Duplicate entry not allowed'';',
'    END IF;',
'   exception when others then',
'    RETURN ''Error while checking duplicate email: '' || SQLERRM;',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_when_button_pressed=>wwv_flow_imp.id(136628856168740212)
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
