'// Show a spinner',
'function showSpinner(regionId) {',
'    var region = $(''#'' + regionId);',
'    region.append(''<div class="loading-spinner"></div>'');',
'    region.find(''.loading-spinner'').css({',
'        position: ''absolute'',',
'        top: ''50%'',',
'        left: ''50%'',',
'        transform: ''translate(-50%, -50%)'',',
'        ''z-index'': 1000,',
'    });',
'}',
'',
'// Hide the spinner',
'function hideSpinner(regionId) {',
'    $(''#'' + regionId).find(''.loading-spinner'').remove();',
'}',
'',
'// Add spinner and refresh the regions',
'function refreshRegionWithSpinner(regionId) {',
'    showSpinner(regionId);',
'    apex.region(regionId).refresh();',
'    setTimeout(function() {',
'        hideSpinner(regionId);',
'    }, 1000); // Hide the spinner after 1 second (adjust as needed)',
'}',
'',
'// Delayed refresh with spinners',
'setTimeout(function() {',
'    refreshRegionWithSpinner(''Qualification'');',
'    refreshRegionWithSpinner(''COURSE_DETAILS'');',
'    refreshRegionWithSpinner(''Employment_History'');',
'    refreshRegionWithSpinner(''Family_details'');',
'}, 1000); // 1 seconds delay',
''))
);
