'        AND VC_APPLICANT_ID = :P8_VC_APPLICANT_ID;',
'',
'    END IF;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        -- Rollback the transaction in case of an error',
'        ROLLBACK;',
'        -- Optionally, log the error or raise it',
'        RAISE_APPLICATION_ERROR(-20001, ''Error occurred: '' || SQLERRM);',
'END;',
'',
'',
'',
''))
,p_attribute_02=>'P8_VC_APPLICANT_ID'
