wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(136673289251740251)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'SAVE'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_applicant_id  VARCHAR2(5); ',
'    L_BLOB_doc BLOB;',
'    MIME VARCHAR2(2000);',
'    FNAME VARCHAR2(2000);',
'    V_BLOB_IMG BLOB;',
'    V_MIME VARCHAR2(2000);',
'    V_FNAME VARCHAR2(2000);',
'    p_body_html  clob;',
'    TMS_SEQ number;',
'',
'BEGIN',
'      ',
'',
'         BEGIN',
'             SELECT BLOB_CONTENT,MIME_TYPE,FILENAME',
'              INTO   L_BLOB_doc,MIME,FNAME',
'              FROM   APEX_APPLICATION_TEMP_FILES',
'              WHERE  NAME=:P8_UPLOAD;',
'              EXCEPTION WHEN NO_DATA_FOUND ',
'              THEN NULL;',
'         END;',
'',
'',
'         BEGIN',
'             SELECT BLOB_CONTENT,MIME_TYPE,FILENAME',
'              INTO   V_BLOB_IMG,V_MIME,V_FNAME',
'              FROM   APEX_APPLICATION_TEMP_FILES',
'              WHERE  NAME=:P8_IMAGE_UPLOAD;',
'              EXCEPTION WHEN NO_DATA_FOUND ',
'              THEN NULL;',
'         END;',
'',
'',
'        -- -- IF :P8_ACTION IN (''A'', ''E'') THEN',
'        --     SELECT NVL(MAX(TO_NUMBER(VC_APPLICANT_ID)), 0) + 1',
'        --       INTO l_applicant_id',
'        --       FROM APPLICANT_DETAILS;',
'       ',
'  begin',
'    -- Insert into APPLICANT_DETAILS table',
'   INSERT INTO APPLICANT_DETAILS (',
'      VC_COMP_CODE,',
'      VC_DEFAULT_COMP,',
'      VC_AUTH_CODE,',
'      DT_MOD_DATE,',
'      VC_APPLICANT_ID,',
'      VC_NAME,',
'      DT_DOB,',
'      VC_FATHER_HUSBAND,',
'      VC_PRESENT_ADDR,',
'      VC_CONTACT,',
'      VC_EMAIL,',
'      VC_PERM_ADDR,',
'      VC_PERM_CONTACT,',
'      VC_GENDER,',
'      VC_MARITAL_STATUS,',
'      VC_HOMETOWN,',
'      VC_EXPERTISE,',
'      CH_EXP_STATUS,',
'      LINKEDIN_ID',
'    --   DESIGNATION',
'   )',
'   VALUES (',
'      :GLOBAL_COMP_CODE,',
'      :GLOBAL_COMP_CODE,',
'      :GLOBAL_USER_CODE,',
'      SYSDATE,',
'      :APPLICANT_ID,',
'      :P8_VC_NAME,',
'      :P8_DT_DOB,',
'      :P8_VC_FATHER_HUSBAND,',
'      :P8_VC_PRESENT_ADDR,',
'      :P8_VC_CONTACT,',
'      :P8_VC_EMAIL,',
'      :P8_VC_PERM_ADDR,',
'      :P8_VC_PERM_CONTACT,',
'      :P8_VC_GENDER,',
'      :P8_VC_MARITAL_STATUS,',
'      :P8_VC_HOMETOWN,',
'      :P8_VC_EXPERTISE,',
'      :P8_FRE_EXP,',
'      :P8_LINKEDIN_ID',
'    --   :P8_DESIGNATION',
'   );',
'   exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error applicant details: '' || SQLERRM);',
'end;',
'   -- Insert records from APEX collection ''QUALIFICATION_DTL'' into ''EDUCATIONAL_QUALIFICATIONS'' table',
'  begin',
'   FOR rec IN (',
'      SELECT',
'         c002 AS VC_QUALIFICATION_ID,',
'         :APPLICANT_ID AS VC_APPLICANT_ID,',
'         c003 AS VC_DEGREE,',
'         c004 AS VC_MAIN_SUBJECT,',
'         c005 AS VC_INSTITUTE_NAME,',
'         c006 AS VC_DURATION,',
'         c007 AS VC_PASSING_YEAR,',
'         c008 AS NUM_PERCENTAGE',
'      FROM apex_collections',
'      WHERE collection_name = ''QUALIFICATION_DTL''',
'   ) LOOP',
'      INSERT INTO EDUCATIONAL_QUALIFICATIONS (',
'         VC_COMP_CODE,',
'         VC_DEFAULT_COMP,',
'         VC_AUTH_CODE,',
'         DT_MOD_DATE,',
'         VC_QUALIFICATION_ID,',
'         VC_APPLICANT_ID,',
'         VC_DEGREE,',
'         VC_MAIN_SUBJECT,',
'         VC_INSTITUTE_NAME,',
'         VC_DURATION,',
'         VC_PASSING_YEAR,',
'         NU_PERCENTAGE',
'      )',
'      VALUES (',
'         :GLOBAL_COMP_CODE,',
'         :GLOBAL_COMP_CODE,',
'         :GLOBAL_USER_CODE,',
'         SYSDATE,',
'         rec.VC_QUALIFICATION_ID,',
'         rec.VC_APPLICANT_ID,',
'         rec.VC_DEGREE,',
'         rec.VC_MAIN_SUBJECT,',
'         rec.VC_INSTITUTE_NAME,',
'         rec.VC_DURATION,',
'         rec.VC_PASSING_YEAR,',
'         rec.NUM_PERCENTAGE',
'      );',
'   END LOOP;',
'   exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error education details: '' || SQLERRM);',
'end;',
'   -- Insert records from APEX collection ''ADDITIONAL_COURSES'' into ''ADDITIONAL_COURSES'' table',
' begin',
'   FOR rec IN (',
'      SELECT',
'         c001 AS VC_COURSE_ID,',
'         :APPLICANT_ID AS VC_APPLICANT_ID,',
'         c003 AS VC_COURSE_NAME,',
'         c004 AS VC_DURATION,',
'         TO_DATE(c005, ''MM-DD-YYYY'') AS DT_COMPLETION_DATE,',
'         c006 AS VC_INSTITUTION',
'      FROM apex_collections',
'      WHERE collection_name = ''ADDITIONAL_COURSES''',
'   ) LOOP',
'      INSERT INTO ADDITIONAL_COURSES (',
'         VC_COMP_CODE,',
'         VC_DEFAULT_COMP,',
'         VC_COURSE_ID,',
'         VC_APPLICANT_ID,',
'         VC_COURSE_NAME,',
'         VC_DURATION,',
'         DT_COMPLETION_DATE,',
'         VC_INSTITUTION',
'      )',
'      VALUES (',
'         :GLOBAL_COMP_CODE,',
'         :GLOBAL_COMP_CODE,',
'         rec.VC_COURSE_ID,',
'         rec.VC_APPLICANT_ID,',
'         rec.VC_COURSE_NAME,',
'         rec.VC_DURATION,',
'         rec.DT_COMPLETION_DATE,',
'         rec.VC_INSTITUTION',
'      );',
'   END LOOP;',
'   exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error additional details: '' || SQLERRM);',
'end;',
'   -- Insert records from APEX collection ''EMPLOYMENT_DTL'' into ''EMPLOYMENT_DETAILS'' table',
' begin',
'   FOR rec IN (',
'      SELECT',
'         c001 AS VC_EMPLOYMENT_ID,',
'         :APPLICANT_ID AS VC_APPLICANT_ID,',
'         c003 AS VC_EMPLOYER_NAME,',
'         c004 AS VC_LOCATION,',
'         TO_DATE(c005, ''MM-DD-YYYY'') AS DT_JOINING_DATE,',
'         TO_DATE(c006, ''MM-DD-YYYY'') AS DT_LEAVING_DATE,',
'         c007 AS VC_DESIGNATION,',
'         c008 AS NUM_SALARY,',
'         c009 AS VC_COUNTRY,',
'         c010 AS VC_STATE,',
'         c011 AS CH_CURRENT_EMPLOYER',
'      FROM apex_collections',
'      WHERE collection_name = ''EMPLOYMENT_DTL''',
'   ) LOOP',
'      INSERT INTO EMPLOYMENT_DETAILS (',
'         VC_COMP_CODE,',
'         VC_DEFAULT_COMP,',
'         VC_EMPLOYMENT_ID,',
'         VC_APPLICANT_ID,',
'         VC_EMPLOYER_NAME,',
'         VC_LOCATION,',
'         DT_JOINING_DATE,',
'         DT_LEAVING_DATE,',
'         VC_DESIGNATION,',
'         NUM_SALARY,',
'         VC_COUNTRY,',
'         VC_STATE,',
'         CH_CURRENT_EMPLOYER',
'      )',
'      VALUES (',
'         :GLOBAL_COMP_CODE,',
'         :GLOBAL_COMP_CODE,',
'         rec.VC_EMPLOYMENT_ID,',
'         rec.VC_APPLICANT_ID,',
'         rec.VC_EMPLOYER_NAME,',
'         rec.VC_LOCATION,',
'         rec.DT_JOINING_DATE,',
'         rec.DT_LEAVING_DATE,',
'         rec.VC_DESIGNATION,',
'         rec.NUM_SALARY,',
'         rec.VC_COUNTRY,',
'         rec.VC_STATE,',
'         rec.CH_CURRENT_EMPLOYER',
'      );',
'   END LOOP;',
'   exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error employment details: '' || SQLERRM);',
'end;',
'   -- Insert records from APEX collection ''FAMILY_DETAILS_COLLECTION'' into ''FAMILY_DETAILS'' table',
'  begin',
'   FOR rec IN (',
'      SELECT',
'         c001 AS VC_FAMILY_ID,',
'         :APPLICANT_ID AS VC_APPLICANT_ID,',
'         c003 AS VC_NAME,',
'         c004 AS VC_RELATION,',
'         c005 AS VC_OCCUPATION,',
'         c006 AS VC_DEPARTMENT,',
'         c007 AS VC_DESIGNATION,',
'         c008 AS NUM_MONTHLY_INCOME',
'      FROM apex_collections',
'      WHERE collection_name = ''FAMILY_DETAILS_COLLECTION''',
'   ) LOOP',
'      INSERT INTO FAMILY_DETAILS (',
'         VC_COMP_CODE,',
'         VC_DEFAULT_COMP,',
'         VC_FAMILY_ID,',
'         VC_APPLICANT_ID,',
'         VC_NAME,',
'         VC_RELATION,',
'         VC_OCCUPATION,',
'         VC_DEPARTMENT,',
'         VC_DESIGNATION,',
'         NU_MONTHLY_INCOME',
'      )',
'      VALUES (',
'         :GLOBAL_COMP_CODE,',
'         :GLOBAL_COMP_CODE,',
'         rec.VC_FAMILY_ID,',
'         rec.VC_APPLICANT_ID,',
'         rec.VC_NAME,',
'         rec.VC_RELATION,',
'         rec.VC_OCCUPATION,',
'         rec.VC_DEPARTMENT,',
'         rec.VC_DESIGNATION,',
'         rec.NUM_MONTHLY_INCOME',
'      );',
'   END LOOP;',
'',
'   exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error family details: '' || SQLERRM);',
'end;',
'   -- Insert into MK_CANDIDATE_DOC table',
'  begin',
'   INSERT INTO MK_CANDIDATE_DOC (',
'      VC_COMP_CODE,',
'      VC_DEFAULT_COMP,',
'      VC_APPLICANT_ID,',
'      BL_CANDIDATE_DOC,',
'      MIMETYPE,',
'      FILENAME,',
'      DT_MOD_DATE,',
'      VC_AUTH_CODE,',
'      DT_LAST_UPDATE',
'   )',
'   VALUES (',
'      :GLOBAL_COMP_CODE,',
'      :GLOBAL_COMP_CODE,',
'      :APPLICANT_ID,',
'      L_BLOB_doc,',
'      MIME,',
'      FNAME,',
'      SYSDATE,',
'      :GLOBAL_USER_CODE,',
'      SYSDATE',
'   );',
'      exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error candidate d details: '' || SQLERRM);',
'end;',
'',
'   -- Insert into APPLICANT_UPLOAD_IMG table',
'   begin',
'   INSERT INTO APPLICANT_UPLOAD_IMG (',
'      VC_COMP_CODE,',
'      VC_DEFAULT_COMP,',
'      VC_APPLICANT_ID,',
'      BL_APPLICANT_IMG,',
'      MIMETYPE,',
'      FILENAME,',
'      DT_MOD_DATE,',
'      VC_AUTH_CODE,',
'      DT_LAST_UPDATE',
'   )',
'   VALUES (',
'      :GLOBAL_COMP_CODE,',
'      :GLOBAL_COMP_CODE,',
'      :APPLICANT_ID,',
'      V_BLOB_IMG,',
'      V_MIME,                ',
'      V_FNAME,',
'      SYSDATE,',
'      :GLOBAL_USER_CODE,',
'      SYSDATE',
'   ); ',
'      exception when others then',
'         ROLLBACK ;',
'        -- Log or output the error message',
'        RAISE_APPLICATION_ERROR(-20001, ''Error applicant image : '' || SQLERRM);',
'end;',
'',
'        -- Truncate all APEX collections after insertion',
'        BEGIN',
'            APEX_COLLECTION.TRUNCATE_COLLECTION(p_collection_name => ''QUALIFICATION_DTL'');',
'            APEX_COLLECTION.TRUNCATE_COLLECTION(p_collection_name => ''ADDITIONAL_COURSES'');',
'            APEX_COLLECTION.TRUNCATE_COLLECTION(p_collection_name => ''EMPLOYMENT_DTL'');',
'            APEX_COLLECTION.TRUNCATE_COLLECTION(p_collection_name => ''FAMILY_DETAILS_COLLECTION'');',
'',
'',
'        EXCEPTION',
'            WHEN OTHERS THEN',
'                -- Handle any errors that may occur while deleting collections',
'                DBMS_OUTPUT.PUT_LINE(''Error truncating collections: '' || SQLERRM);',
'        END;',
'',
'',
'------------- Trigger mail after submit the form --------------',
'',
'     -- Send email using APEX_MAIL',
'-- APEX_MAIL.SEND(',
'--     p_to         => :P8_VC_EMAIL,  -- Recipient''s email address',
'--     p_from       => ''offshore.tms@essindia.com'', -- Sender email',
