'',
'-- Push queued mail to SMTP server',
'-- APEX_MAIL.PUSH_QUEUE;',
'',
'   p_body_html := ',
'    ''<html>',
'        <body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">',
'            <div style="max-width: 650px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 8px; background-color: #f9f9f9;">',
'                <h2 style="color: #4CAF50; text-align: center;">Application Confirmation</h2>',
