wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(136671682993740250)
,p_process_sequence=>30
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Qualification'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_collection_name  VARCHAR2(100) := ''QUALIFICATION_DTL'';',
'    l_seq_id           NUMBER;',
'    l_exists           BOOLEAN := FALSE; -- Default value, will change based on the query',
'    l_new_id           NUMBER;',
'    l_duplicate_exists BOOLEAN := FALSE; -- For checking duplicates based on Degree, Main Subject, Institute Name',
'    l_duplicate_deg_inst BOOLEAN := FALSE; -- For checking duplicates based on Degree and Institute Name',
'BEGIN',
'    -- Ensure the collection exists',
'    IF NOT APEX_COLLECTION.COLLECTION_EXISTS(p_collection_name => l_collection_name) THEN',
'        APEX_COLLECTION.CREATE_COLLECTION(p_collection_name => l_collection_name);',
'    END IF;',
'',
'    -- Check if the item already exists in the collection (based on seq_id)',
'    BEGIN',
'        SELECT seq_id',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND seq_id = :P8_SEQ_ID;',
'',
'        l_exists := TRUE; -- Item exists',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            -- No record found, set l_exists to FALSE',
'            l_exists := FALSE; ',
'            l_seq_id := NULL; -- In case the item doesn''t exist, make sure seq_id is null',
'    END;',
'',
'',
'        -- Check for duplicate Degree  ',
'    BEGIN',
'        SELECT seq_id',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND c003 = :P8_VC_DEGREE',
'           AND (:P8_SEQ_ID IS NULL OR seq_id != :P8_SEQ_ID); -- Exclude current record from the check',
'',
'        l_duplicate_exists := TRUE; ',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            -- No duplicate found',
'            l_duplicate_exists := FALSE;',
'    END;',
'',
'',
'    BEGIN',
'        SELECT seq_id',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND c003 = :P8_VC_DEGREE',
'           AND c005 = :P8_VC_INSTITUTE_NAME',
'           AND (:P8_SEQ_ID IS NULL OR seq_id != :P8_SEQ_ID); -- Exclude current record from the check',
'',
'        l_duplicate_deg_inst := TRUE; -- Duplicate found for Degree + Institute Name',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            -- No duplicate found',
'            l_duplicate_deg_inst := FALSE;',
'    END;',
'',
'    -- Handle duplicate case for Degree + Institute Name',
'    IF l_duplicate_exists THEN',
'        HTP.P(''QUALI''); -- Message indicating that this combination already exists',
'        ',
'    ELSIF l_duplicate_deg_inst THEN',
'        HTP.P(''QUALI1''); -- Message indicating that this combination already exists',
'    ELSE',
'        -- Proceed with update or insertion logic',
'        IF :P8_SEQ_ID IS NOT NULL THEN',
'            -- If P8_SEQ_ID is provided, update the existing member',
'            IF l_exists THEN',
'                APEX_COLLECTION.UPDATE_MEMBER(',
'                    p_collection_name => l_collection_name,',
'                    p_seq             => l_seq_id,',
'                    p_c002            => :P8_SEQ_ID,  -- Retaining P8_SEQ_ID as C002',
'                    p_c003            => :P8_VC_DEGREE,',
'                    p_c004            => :P8_VC_MAIN_SUBJECT,',
'                    p_c005            => :P8_VC_INSTITUTE_NAME,',
'                    p_c006            => :P8_VC_DURATION,',
'                    p_c007            => :P8_VC_PASSING_YEAR,',
'                    p_c008            => :P8_NUM_PERCENTAGE',
'                );',
'            ELSE',
'                -- Handle case where P8_SEQ_ID doesn''t match an existing record',
'                RAISE_APPLICATION_ERROR(-20001, ''The specified record does not exist in the collection.'');',
'            END IF;',
'        ELSE',
'            -- If P8_SEQ_ID is not provided, generate a new ID and add a new member',
'            SELECT NVL(MAX(TO_NUMBER(c002)), 0) + 1',
'              INTO l_new_id',
'              FROM apex_collections',
'             WHERE collection_name = l_collection_name;',
'',
'            -- Add a new member to the collection',
'            APEX_COLLECTION.ADD_MEMBER(',
'                p_collection_name => l_collection_name,',
'                p_c002            => l_new_id, -- New unique ID for this member',
'                p_c003            => :P8_VC_DEGREE,',
'                p_c004            => :P8_VC_MAIN_SUBJECT,',
'                p_c005            => :P8_VC_INSTITUTE_NAME,',
'                p_c006            => :P8_VC_DURATION,',
'                p_c007            => :P8_VC_PASSING_YEAR,',
'                p_c008            => :P8_NUM_PERCENTAGE',
'            );',
'        END IF;',
'    END IF;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        -- Output error message in case of an exception',
'        HTP.P(''Error: '' || SQLERRM);',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>4173847710310453
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(136672078623740251)
,p_process_sequence=>40
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'ADDITIONAL_COURSE'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_collection_name  VARCHAR2(100) := ''ADDITIONAL_COURSES'';',
'    l_seq_id           NUMBER;',
'    l_exists           BOOLEAN := FALSE;  -- Default as FALSE',
'    l_new_id           NUMBER;',
'',
'BEGIN',
'    -- Ensure the collection exists',
'    IF NOT APEX_COLLECTION.COLLECTION_EXISTS(p_collection_name => l_collection_name) THEN',
'        APEX_COLLECTION.CREATE_COLLECTION(p_collection_name => l_collection_name);',
'    END IF;',
'',
'    -- Check if the item already exists in the collection (based on P8_SEQ_ID_1)',
'    BEGIN',
'        -- Attempt to find the seq_id of the existing item',
'        SELECT seq_id',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND seq_id = :P8_SEQ_ID_1;  -- Use P8_SEQ_ID_1 here',
'',
'        l_exists := TRUE; -- If found, item exists',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            l_exists := FALSE; -- Item does not exist',
'            l_seq_id := NULL;  -- No existing seq_id',
'    END;',
'',
'    -- Now, handle the logic for duplicate check',
'    -- Check for duplicate records based on combination of details excluding current record being updated',
'    BEGIN',
'        SELECT seq_id',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND c003 = :P8_VC_COURSE_NAME',
'           AND c006 = :P8_VC_INSTITUTION',
'           AND (:P8_SEQ_ID_1 IS NULL OR seq_id != :P8_SEQ_ID_1); -- Exclude current record',
'',
'        l_exists := TRUE; -- Duplicate record found',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            l_exists := FALSE; -- No duplicate found',
'    END;',
'',
'    -- Handle duplicate case',
'    IF l_exists THEN',
'        -- Return a message for duplicate record',
'        HTP.P(''COURSE''); -- Output ''COURSE'' to indicate duplicate record',
'    ELSE',
'        -- Now we perform the update or insert',
'        IF :P8_SEQ_ID_1 IS NOT NULL AND l_exists = FALSE THEN',
'            -- If P8_SEQ_ID_1 is provided and item exists, update the existing member',
'            APEX_COLLECTION.UPDATE_MEMBER(',
'                p_collection_name => l_collection_name,',
'                p_seq             => l_seq_id,',
'                p_c001            => :P8_SEQ_ID_1,                -- Retaining existing seq_id as c001',
