'                p_c003            => :P8_VC_COURSE_NAME,',
'                p_c004            => :P8_VC_CDURATION,',
'                p_c005            => :P8_DT_COMPLETION_DATE,',
'                p_c006            => :P8_VC_INSTITUTION',
'            );',
'        ELSE',
'            -- Generate a new unique ID for P8_VC_COURSE_ID when adding a new member',
'            SELECT NVL(MAX(TO_NUMBER(c001)), 0) + 1',
'              INTO l_new_id',
'              FROM apex_collections',
'             WHERE collection_name = l_collection_name;',
'',
'            -- Add a new member to the collection',
'            APEX_COLLECTION.ADD_MEMBER(',
'                p_collection_name => l_collection_name,',
'                p_c001            => l_new_id, -- New unique ID for this member',
'                p_c002            => :P8_VC_CAPPLICANT_ID,',
'                p_c003            => :P8_VC_COURSE_NAME,',
'                p_c004            => :P8_VC_CDURATION,',
'                p_c005            => :P8_DT_COMPLETION_DATE,',
'                p_c006            => :P8_VC_INSTITUTION',
'            );',
'        END IF;',
'    END IF;',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        -- Handle error and provide the error message',
'        HTP.P(''Error: '' || SQLERRM);',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>4174243340310454
);
