'            p_c002            => :P8_EVC_APPLICANT_ID,',
'            p_c003            => :P8_VC_EMPLOYER_NAME,',
'            p_c004            => :P8_VC_LOCATION,',
'            p_c005            => :P8_DT_JOINING_DATE,',
'            p_c006            => :P8_DT_LEAVING_DATE, -- Update LEAVING_DATE',
'            p_c007            => :P8_VC_DESIGNATION,',
'            p_c008            => :P8_NUM_SALARY,',
'            p_c009            => :P8_COUNTRY,',
'            p_c010            => :P8_STATE,',
'            p_c011            => :P8_CURRENT_EMPLOYER',
'        );',
'    ELSE',
'       -- Validation for Joining Date and Leaving Date',
'-- BEGIN',
