'--     END IF;',
'-- EXCEPTION',
'--     WHEN NO_DATA_FOUND THEN',
'--         NULL; -- No validation required if no previous records exist',
'-- END;',
'',
'',
'        -- Check for duplicate records based on combination of details',
'        BEGIN',
'            SELECT seq_id',
'              INTO l_seq_id',
'              FROM apex_collections',
'             WHERE collection_name = l_collection_name',
'               AND c003 = :P8_VC_EMPLOYER_NAME',
'               AND c005 = :P8_DT_JOINING_DATE',
'               AND c006 = :P8_DT_LEAVING_DATE',
'               AND c007 = :P8_VC_DESIGNATION;',
'',
'            l_exists := TRUE; -- Duplicate record found',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'                l_exists := FALSE; -- No duplicate found',
'        END;',
'',
'        -- Handle duplicate case',
'        IF l_exists THEN',
'            HTP.P(''EMP''); -- Output ''EMP'' to indicate duplicate record',
'        END IF;',
'',
'            -- Check for duplicate records based on combination of details',
'        BEGIN',
'            SELECT seq_id',
'              INTO l_seq_id',
'              FROM apex_collections',
'             WHERE collection_name = l_collection_name',
'               AND c003 = :P8_VC_EMPLOYER_NAME',
'               AND c007 = :P8_VC_DESIGNATION;',
'',
'            l_exists := TRUE; -- Duplicate record found',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
