,p_process_sequence=>60
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Family Detail'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_collection_name  VARCHAR2(100) := ''FAMILY_DETAILS_COLLECTION'';',
'    l_seq_id           NUMBER;',
'    l_exists           BOOLEAN := FALSE; -- Tracks existence by SEQ_ID',
'    l_duplicate_found  BOOLEAN := FALSE; -- Tracks duplicate check',
'    l_new_id           NUMBER;',
'',
'BEGIN',
'    -- Ensure the collection exists',
'    IF NOT APEX_COLLECTION.COLLECTION_EXISTS(l_collection_name) THEN',
'        APEX_COLLECTION.CREATE_COLLECTION(p_collection_name => l_collection_name);',
'    END IF;',
'',
'    -- Check if the record exists based on SEQ_ID',
'    BEGIN',
'        SELECT seq_id   ',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND seq_id = :P8_SEQ_ID_3;',
'',
'        l_exists := TRUE; -- Record exists',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            l_exists := FALSE; -- Record does not exist',
'    END;',
'',
'    -- Check for duplicate records based on other attributes',
'    BEGIN',
'        SELECT COUNT(*)',
'          INTO l_seq_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name',
'           AND c003 = :P8_MEMBER_NAME',
'           AND c004 = :P8_VC_RELATION',
'           AND c005 = :P8_VC_OCCUPATION',
'           AND c006 = :P8_VC_DEPARTMENT',
'           AND c007 = :P8_VC_PREV_DESIGNATION',
'           AND c008 = :P8_NUM_MONTHLY_INCOME',
'           AND (:P8_SEQ_ID_3 IS NULL OR seq_id != :P8_SEQ_ID_3); -- Exclude the current record if updating',
'',
'        IF l_seq_id > 0 THEN',
'            l_duplicate_found := TRUE; -- Duplicate record exists',
'        ELSE',
'            l_duplicate_found := FALSE; -- No duplicate record found',
'        END IF;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            l_duplicate_found := FALSE; -- No duplicates found',
'    END;',
'',
'    -- Handle duplicate case',
'    IF l_duplicate_found THEN',
'        HTP.P(''FAMILY''); -- Output message for duplicate record',
'        RETURN; -- Exit if duplicate is found',
'    END IF;',
'',
'    -- Update the existing record if it exists',
'    IF l_exists THEN',
'        APEX_COLLECTION.UPDATE_MEMBER(',
'            p_collection_name => l_collection_name,',
'            p_seq             => :P8_SEQ_ID_3, -- Use the provided SEQ_ID for updating',
'            p_c001            => :P8_SEQ_ID_3,',
'            p_c002            => :P8_VC_FAPPLICANT_ID,',
'            p_c003            => :P8_MEMBER_NAME,',
'            p_c004            => :P8_VC_RELATION,',
'            p_c005            => :P8_VC_OCCUPATION,',
'            p_c006            => :P8_VC_DEPARTMENT,',
'            p_c007            => :P8_VC_PREV_DESIGNATION,',
'            p_c008            => :P8_NUM_MONTHLY_INCOME',
'        );',
'    ELSE',
'        -- Generate a new unique ID for the new record',
'        SELECT NVL(MAX(TO_NUMBER(c001)), 0) + 1',
'          INTO l_new_id',
'          FROM apex_collections',
'         WHERE collection_name = l_collection_name;',
'',
'        -- Add a new record to the collection',
'        APEX_COLLECTION.ADD_MEMBER(',
'            p_collection_name => l_collection_name,',
'            p_c001            => l_new_id, -- Assign the new unique ID',
'            p_c002            => :P8_VC_FAPPLICANT_ID,',
'            p_c003            => :P8_MEMBER_NAME,',
'            p_c004            => :P8_VC_RELATION,',
'            p_c005            => :P8_VC_OCCUPATION,',
'            p_c006            => :P8_VC_DEPARTMENT,',
'            p_c007            => :P8_VC_PREV_DESIGNATION,',
'            p_c008            => :P8_NUM_MONTHLY_INCOME',
'        );',
'    END IF;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        -- Handle and output any unexpected errors',
'        HTP.P(''Error: '' || SQLERRM);',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>4175011898310454
);
