'IF :P21_EMAIL IS NULL THEN ',
'   RETURN ''Email can not be null'';',
'END IF;   ',
'',
'',
'IF :P21_PHONE_NUMBER IS NULL THEN ',
'   RETURN ''Phone number can not be null'';',
'END IF;   ',
'',
'',
'',
'DECLARE',
'   l_user_exists NUMBER;',
'BEGIN',
'   -- Check if the username (email) already exists',
'   SELECT COUNT(*) ',
'   INTO l_user_exists ',
'   FROM TEMP_USER ',
'   WHERE UPPER(VC_USER_NAME) = UPPER(:P21_EMAIL);',
'',
'   -- If the username exists, raise an error',
'   IF l_user_exists > 0 THEN',
'      RETURN(''User already sign in please checked on your email and click on sign up.'');',
'   END IF;',
'END;',
'',
'',
'',
'',
'DECLARE',
'    l_exists NUMBER;',
'BEGIN',
'    -- Check if the email exists in the PRE_HIRING_FORM table',
'    SELECT COUNT(*) ',
'    INTO l_exists',
'    FROM PRE_HIRING_FORM ',
'    WHERE UPPER(VC_EMAIL) = UPPER(:P21_EMAIL);',
'',
'    IF l_exists = 0 THEN',
'        RETURN ''This email does not match from resume.'';',
'    END IF;',
'',
'    RETURN NULL; -- Validation passed',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_when_button_pressed=>wwv_flow_imp.id(116271445430863562)
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
