,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'   l_active_count   NUMBER;',
'   l_inactive_count NUMBER;',
'BEGIN',
'   -- Check if email exists and is active',
'   SELECT COUNT(*) ',
'   INTO l_active_count ',
'   FROM TEMP_USER ',
'   WHERE UPPER(VC_USER_NAME) = UPPER(:P21_EMAIL)',
'   AND CH_ACTIVE = ''Y'';',
'',
'   IF l_active_count > 0 THEN',
'      RETURN NULL; -- Active user found, validation passed',
'   END IF;',
'',
'   -- Check if email exists but is inactive',
'   SELECT COUNT(*) ',
'   INTO l_inactive_count ',
'   FROM TEMP_USER ',
'   WHERE UPPER(VC_USER_NAME) = UPPER(:P21_EMAIL)',
'   AND CH_ACTIVE = ''N'';',
'',
'   IF l_inactive_count > 0 THEN',
'      RETURN ''This email already use for sign up.'';',
'   END IF;',
'',
'   -- Email not found at all',
'   RETURN ''Please register first.'';',
'END;'))
