,p_process_name=>'Login'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'   l_id NUMBER;',
'   l_password VARCHAR2(10);',
'   l_new_id NUMBER;',
'   l_special_chars CONSTANT VARCHAR2(10) := ''!@#$%^&*'';',
'   l_random_special VARCHAR2(1);',
'   l_username_prefix VARCHAR2(2);',
'   l_random_string VARCHAR2(4);',
'   p_body_html CLOB;',
'   TMS_SEQ     number;',
'   v_domain    varchar2(200);',
'   v_protocol  varchar2(200);',
'   l_url varchar2(100);',
'BEGIN',
'   -- Check if the email exists in PRE_HIRING_FORM',
'   BEGIN',
'      SELECT  MAX(to_number(ID))',
'      INTO l_id',
'      FROM PRE_HIRING_FORM ',
'      WHERE UPPER(VC_EMAIL) = UPPER(:P21_EMAIL);',
'',
'      :APPLICANT_ID := l_id;',
'',
'   EXCEPTION',
'      WHEN NO_DATA_FOUND THEN',
'         RAISE_APPLICATION_ERROR(-20001, ''This email does not match from resume.'');',
'      WHEN TOO_MANY_ROWS THEN',
'         RAISE_APPLICATION_ERROR(-20002, ''Multiple resumes found with this email.'');',
'   END;',
'',
'   -- Generate a new User ID',
'   SELECT NVL(MAX(TO_NUMBER(USER_ID)), 0) + 1',
'   INTO l_new_id',
'   FROM TEMP_USER;',
'',
'   -- Extract first 2 letters of username and capitalize the first letter',
'   l_username_prefix := INITCAP(SUBSTR(:P21_USERNAME, 1, 2));',
'',
'   -- Generate a random special character',
'   l_random_special := SUBSTR(l_special_chars, DBMS_RANDOM.VALUE(1, LENGTH(l_special_chars)), 1);',
'',
'   -- Generate a random string of 4 alphanumeric characters',
'   l_random_string := DBMS_RANDOM.STRING(''A'', 4);  ',
'',
'   -- Ensure User ID is exactly 3 digits (padded with zeros if necessary)',
'   l_new_id := LPAD(l_new_id, 3, ''0'');',
'',
'   -- Construct the password',
'   l_password := l_username_prefix || l_new_id || l_random_special || l_random_string;',
'',
'   -- Insert into TEMP_USER table',
'   INSERT INTO TEMP_USER (',
'      VC_COMP_CODE,',
'      NAME,',
'      VC_USER_NAME,',
'      VC_PASSWORD,',
'      VC_EMAIL,',
'      VC_MOBILE,',
'      DT_CRT_DATE,',
'      CH_ACTIVE,',
'      USER_ID',
'   )',
'   VALUES (',
'      :GLOBAL_COMP_CODE,',
'      :P21_USERNAME,',
'      :P21_EMAIL,',
