'    IF v_protocol IS NULL THEN',
'        -- fallback to https if not found',
'        v_protocol := ''https'';',
'    END IF;',
'',
' -- Construct applicant form URL without ID',
'    l_url :=  v_protocol || ''://'' || v_domain ||''/ords/f?p=120:21'';',
'',
'   -- Construct email body',
'   p_body_html := ',
'    --   ''<html><body>'' ||',
'    --   ''<p>Dear <strong>'' || :P21_USERNAME || ''</strong>,</p>'' ||',
'    --   ''<p>Please find below your access credentials required to proceed with the next steps of the recruitment process at ESS:</p>'' ||',
'    --   ''<p><strong>Login URL: </strong>''|| l_url ||''</p>'' ||',
'    --   ''<p><strong>Username: </strong>''|| :P21_EMAIL ||''</p>'' ||',
'    --   ''<p><strong>Password: </strong>''|| l_password ||''</p>'' ||',
