'    --   ''<p style="margin: 0; padding: 0;"><strong>Eastern Software Solutions Private Limited</strong></p>'' ||',
'    --   ''<p style="margin: 0; padding: 0;">Lotus Business Park Power House,</b><br>',
'    --             3rd floor, Tower B, Plot No. 8,</b><br>',
