'    --   ''<p style="margin: 0; padding: 0;">Tel: + 91 (120) 4212931 - 39</p>'' ||',
'    --   ''<p style="margin: 0; padding: 0;">Web: <a href="http://www.ebizframe.com" target="_blank">www.ebizframe.com</a></p>'' ||',
'    --   ''<p style="margin: 0; padding: 0;">Web: <a href="http://www.essindia.com" target="_blank">www.essindia.com</a></p>'' ||',
