'      ''<p style="margin: 0; padding: 0;">Web: <a href="http://www.essindia.com" target="_blank">www.essindia.com</a></p>'' ||',
'    ''</body></html>'';',
'',
'',
'           ----saurabh singh ----- Send mail to user-------21-07-25',
'',
'      -- Generate sequence for logging',
'    SELECT WSTMS.SEND_TMS_MAIL.NEXTVAL ',
'    INTO TMS_SEQ ',
'    FROM dual;',
'',
'    INSERT INTO HCM.EMAIL (ID, VC_COMP_CODE, VC_DOC_NO, DT_DOC_DATE, CH_TRAN_TYPE, VC_RECIPENT_EMAIL, VC_SUBJECT, ',
'    VC_RECEIPENT_NAME, VC_SENDER_NAME, CH_SENT_STATUS, DT_MOD_DATE, VC_BCC_EMAIL, VC_MESSAGE)',
'     VALUES (TMS_SEQ, :GLOBAL_COMP_CODE ,''IH'' ,SYSDATE, ''HI'', :P21_EMAIL, ''Your Registration Successfully'', :P21_USERNAME, ',
'     ''ESS HR Team'', ''N'', SYSDATE, NULL, p_body_html);',
'   -- Send email',
